INSERT INTO public.nightclub_quests (club_id, npc_id, title, description, quest_type, energy_cost, rewards, dialogue, chain_id, chain_position) VALUES
('f9ef6b4f-c2aa-417e-a43f-c4b20b5d5bca', 'berghain_bouncer_sven', 'The Door Test', 'Sven the legendary bouncer evaluates whether you belong inside.', 'one_time', 15, '{"cash": 0, "fame": 120, "xp": 40}', '[{"id":"d1","speaker":"Sven","text":"You stand in line for hours. Finally you reach the front. Sven looks you up and down without expression.","choices":[{"id":"c1a","text":"Stay calm, make eye contact, say nothing.","next_node_id":"d2","effects":{"respect":5}},{"id":"c1b","text":"Tell him you are a DJ playing later tonight.","next_node_id":"d2","effects":{"affinity":3}}]},{"id":"d2","speaker":"Sven","text":"...Go in. Do not take photos.","choices":[{"id":"c2","text":"Nod and enter silently.","next_node_id":null}]}]', NULL, NULL),
('86597b75-b91a-4bd3-aced-39e18bed3949', 'tresor_dj_resident', 'Vault Sessions', 'The Tresor resident DJ challenges you to a back-to-back set in the basement vault.', 'one_time', 20, '{"cash": 350, "fame": 100, "xp": 35}', '[{"id":"d1","speaker":"Resident DJ","text":"The vault is where techno was born in Berlin. Raw concrete, pure sound. Can you handle it?","choices":[{"id":"c1a","text":"I live for dark, industrial techno.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I will bring my own flavor to the vault.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Resident DJ","text":"Good. B2B, two hours, no requests. Just us and the machines.","choices":[{"id":"c2","text":"Lets go.","next_node_id":null}]}]', NULL, NULL),
('69587acf-9d75-4727-b43e-a82d6fdc6cd9', 'marquee_promoter_vince', 'Celebrity Guest List', 'Vince the promoter needs you to work the VIP section for a celebrity after-party.', 'one_time', 20, '{"cash": 800, "fame": 200, "xp": 45}', '[{"id":"d1","speaker":"Vince Romano","text":"A-listers are coming tonight. I need a DJ who can read the room AND keep the paparazzi happy. You in?","choices":[{"id":"c1a","text":"I can play the hits and keep the energy VIP-level.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I play what moves people, celebrities or not.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Vince Romano","text":"Perfect. Bottle service starts at midnight. Do not blow this.","choices":[{"id":"c2","text":"Consider it handled.","next_node_id":null}]}]', NULL, NULL),
('51d7119d-eaa5-4d14-b364-77ba8a32ada0', 'output_sound_eng', 'The Funktion-One Challenge', 'The sound engineer wants to test whether you can truly utilize their legendary sound system.', 'one_time', 18, '{"cash": 400, "fame": 90, "xp": 35}', '[{"id":"d1","speaker":"Audio Engineer","text":"This Funktion-One system is worth more than most cars. Most DJs play too loud and muddy the bass. Show me you understand dynamics.","choices":[{"id":"c1a","text":"Dynamics are everything. Build the drops, don not slam them.","next_node_id":"d2","effects":{"respect":6}},{"id":"c1b","text":"I have studied sound design. Let me show you.","next_node_id":"d2","effects":{"affinity":4}}]},{"id":"d2","speaker":"Audio Engineer","text":"Here is the booth. Two-hour slot. Make this system sing.","choices":[{"id":"c2","text":"*steps behind the decks*","next_node_id":null}]}]', NULL, NULL),
('a60b201e-7ab8-4aa3-a019-12910139acc9', 'amnesia_owner_martin', 'Sunrise Set', 'The legendary 6am sunrise slot at Amnesia. Only the worthy get to play it.', 'one_time', 25, '{"cash": 1200, "fame": 300, "xp": 60}', '[{"id":"d1","speaker":"Martin Ferrer","text":"The sunrise set at Amnesia is sacred. 6am, the foam cannons have stopped, and 3000 people are still dancing. You think you can hold them?","choices":[{"id":"c1a","text":"I was born for the sunrise. Euphoric, uplifting, transcendent.","next_node_id":"d2","effects":{"affinity":6}},{"id":"c1b","text":"I will take them on a journey they will never forget.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Martin Ferrer","text":"The terrace is yours. Make Ibiza remember your name.","choices":[{"id":"c2","text":"This is my moment.","next_node_id":null}]}]', NULL, NULL),
('f1d40276-961e-4a09-891f-86bd8cdd9bc6', 'ushuaia_booker_sofia', 'Pool Party Audition', 'Sofia books the daytime pool party DJs. She wants to hear your outdoor set.', 'one_time', 20, '{"cash": 900, "fame": 250, "xp": 50}', '[{"id":"d1","speaker":"Sofia Mendez","text":"Ushuaia pool parties are broadcast worldwide. Our DJs play to influencers, tourists, and industry people simultaneously. Can you handle all three?","choices":[{"id":"c1a","text":"I know how to build a daytime set — upbeat, vocal, irresistible.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"The music does the talking. Give me the slot.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Sofia Mendez","text":"Pool stage, 3pm Saturday. Do not disappoint.","choices":[{"id":"c2","text":"See you poolside.","next_node_id":null}]}]', NULL, NULL),
('8e139d75-e7c2-44e1-9355-52617c29c51d', 'subclub_dj_harri', 'Subculture Initiation', 'Harri wants to see if you understand the Sub Club philosophy before letting you play.', 'one_time', 15, '{"cash": 300, "fame": 80, "xp": 30}', '[{"id":"d1","speaker":"Harri","text":"Sub Club has been running since 1987. We do not follow trends. We set them. What do you bring that is different?","choices":[{"id":"c1a","text":"I dig deep. Rare vinyl, forgotten tracks, future classics.","next_node_id":"d2","effects":{"respect":6}},{"id":"c1b","text":"I bring energy and connection. The crowd and I become one.","next_node_id":"d2","effects":{"affinity":5}}]},{"id":"d2","speaker":"Harri","text":"Right answer. Friday warm-up slot is yours. Prove yourself.","choices":[{"id":"c2","text":"I will not let you down.","next_node_id":null}]}]', NULL, NULL),
('92646fac-668f-4f65-ba19-77f76bc7c326', 'motion_promoter_jay', 'Warehouse Takeover', 'Jay runs the warehouse events at Motion and needs a DJ for their biggest night.', 'one_time', 20, '{"cash": 600, "fame": 150, "xp": 40}', '[{"id":"d1","speaker":"Jay Bristol","text":"Motion warehouse holds 2000 people. We are doing a drum and bass vs techno night. Which side are you on?","choices":[{"id":"c1a","text":"Techno. Heavy, relentless, Bristol-dark.","next_node_id":"d2","effects":{"affinity":4}},{"id":"c1b","text":"D and B. Fast, furious, full of energy.","next_node_id":"d2","effects":{"affinity":4}}]},{"id":"d2","speaker":"Jay Bristol","text":"Good pick. Room 2 is yours. Make it shake.","choices":[{"id":"c2","text":"Consider it done.","next_node_id":null}]}]', NULL, NULL),
('71620d74-07e2-4453-9185-8c84c46680c7', 'circus_owner_yousef', 'The Baltic Triangle Test', 'Yousef, Circus founder, is scouting new talent for their flagship night.', 'one_time', 18, '{"cash": 500, "fame": 120, "xp": 35}', '[{"id":"d1","speaker":"Yousef","text":"Circus has hosted every major name in house music. But I am always looking for the next big thing. Play me something.","choices":[{"id":"c1a","text":"*drops a deep, groovy house track*","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"*starts with a classic before building into something new*","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Yousef","text":"I like what I hear. Support slot next Saturday. Do not be late.","choices":[{"id":"c2","text":"I will be there early.","next_node_id":null}]}]', NULL, NULL),
('ef4b8f81-5c97-4629-b148-9cadde3c1b2d', 'smartbar_resident_derrick', 'Chicago Heritage', 'A house music legend tests your knowledge of Chicago house origins.', 'one_time', 15, '{"cash": 350, "fame": 100, "xp": 35}', '[{"id":"d1","speaker":"Derrick","text":"You are standing in the birthplace of house music. Frankie Knuckles played a mile from here. What does Chicago house mean to you?","choices":[{"id":"c1a","text":"It is the soul of electronic music. 4/4, gospel vocals, raw emotion.","next_node_id":"d2","effects":{"respect":6}},{"id":"c1b","text":"It means freedom. Everyone welcome on the dance floor.","next_node_id":"d2","effects":{"affinity":5}}]},{"id":"d2","speaker":"Derrick","text":"You get it. Take the booth. Show these people what it means.","choices":[{"id":"c2","text":"For Chicago.","next_node_id":null}]}]', NULL, NULL),
('b22ade1d-b329-4807-b996-69b149b3a77d', 'space_terrace_dj', 'Terrace Marathon', 'The terrace at Space is legendary for 24-hour marathon sets. Can you survive?', 'one_time', 25, '{"cash": 700, "fame": 180, "xp": 50}', '[{"id":"d1","speaker":"Terrace DJ","text":"Space terrace does not close. DJs have played 12-hour sets here under the Miami sun. You want in?","choices":[{"id":"c1a","text":"I can read a crowd for hours. Bring it on.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I will pace myself and take the crowd on a journey.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Terrace DJ","text":"6am to noon. The sun will be brutal but the vibes are unmatched.","choices":[{"id":"c2","text":"I will bring sunscreen and records.","next_node_id":null}]}]', NULL, NULL),
('3895416f-5697-499c-8dfd-c26bd37d0d23', 'liv_manager_david', 'The VIP Test', 'LIV manager wants a DJ who can handle the most demanding crowd in Miami.', 'one_time', 20, '{"cash": 1000, "fame": 250, "xp": 45}', '[{"id":"d1","speaker":"David Grutman","text":"LIV is where athletes, rappers, and models party. They do not care about your genre — they want energy. Pure, undeniable energy.","choices":[{"id":"c1a","text":"I bring heat. Open format, high energy, non-stop bangers.","next_node_id":"d2","effects":{"affinity":6}},{"id":"c1b","text":"I will curate a set that keeps every table spending.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"David Grutman","text":"Thursday night trial. Pack the room and you are in the rotation.","choices":[{"id":"c2","text":"Thursday it is.","next_node_id":null}]}]', NULL, NULL),
('f505da4c-c092-4cb0-8413-a9fd6b41b311', 'xs_booker_jesse', 'Sin City Residency', 'The XS talent booker is considering you for a Vegas residency.', 'one_time', 25, '{"cash": 2000, "fame": 400, "xp": 65}', '[{"id":"d1","speaker":"Jesse Waits","text":"Vegas residencies are where DJs become brands. We are talking six figures a night for the right act. But you need to prove you can fill 4000 spots on a Tuesday.","choices":[{"id":"c1a","text":"I have the following and the music to pack any room, any night.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"Build my brand through the music and the crowd will come.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Jesse Waits","text":"One trial night. XS pool, sunset slot. Make believers out of the Vegas crowd.","choices":[{"id":"c2","text":"Vegas, here I come.","next_node_id":null}]}]', NULL, NULL),
('2bd038a7-2d9a-41e5-ac77-da18a9ef186c', 'blacksheep_owner_maz', 'Underground Credibility', 'Maz runs London''s most authentic underground club. Earn her respect.', 'one_time', 12, '{"cash": 200, "fame": 60, "xp": 25}', '[{"id":"d1","speaker":"Maz","text":"The Black Sheep does not book names. We book taste. Play me something that proves you have ears.","choices":[{"id":"c1a","text":"*plays an obscure UK garage white label*","next_node_id":"d2","effects":{"respect":6}},{"id":"c1b","text":"*plays a deep cut from a local producer*","next_node_id":"d2","effects":{"affinity":5}}]},{"id":"d2","speaker":"Maz","text":"Interesting. You have got taste. Wednesday residency, prove yourself weekly.","choices":[{"id":"c2","text":"I will make Wednesdays special.","next_node_id":null}]}]', NULL, NULL),
('b5ed97e8-5313-4fc4-b3ab-4c841596c09f', 'wire_owner_tom', 'Basement Sessions', 'Tom runs Wire legendary basement room. He needs a new resident.', 'one_time', 15, '{"cash": 250, "fame": 70, "xp": 28}', '[{"id":"d1","speaker":"Tom","text":"Wire basement is pure energy. Low ceilings, sweating walls, 200 people going mental. You need stamina and skill down there.","choices":[{"id":"c1a","text":"Small rooms, big energy. That is where I thrive.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I will match the intensity of the room.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Tom","text":"Friday opening set. Warm them up proper — no peaking too early.","choices":[{"id":"c2","text":"Slow build, maximum impact.","next_node_id":null}]}]', NULL, NULL),
('a41e10b4-aac2-4e97-a708-3f37634cc246', 'paradiso_curator_eva', 'Church of Sound', 'Eva curates the electronic nights in this converted church.', 'one_time', 18, '{"cash": 500, "fame": 130, "xp": 38}', '[{"id":"d1","speaker":"Eva van Berg","text":"Paradiso is a church converted into a temple of music. The acoustics are divine — literally. Your music must honor the space.","choices":[{"id":"c1a","text":"I will craft a set that feels spiritual and transcendent.","next_node_id":"d2","effects":{"affinity":6}},{"id":"c1b","text":"The architecture inspires me. I will make the room breathe.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Eva van Berg","text":"Saturday night, main hall. The congregation awaits.","choices":[{"id":"c2","text":"Amen to that.","next_node_id":null}]}]', NULL, NULL),
('7bada165-9a08-493c-8211-7515f56724d7', 'caves_dj_angus', 'Ancient Grooves', 'Angus McBeat wants a collaborator for a special event in the 500-year-old vaults.', 'one_time', 15, '{"cash": 300, "fame": 80, "xp": 30}', '[{"id":"d1","speaker":"Angus McBeat","text":"These vaults have been here since the 1700s. Plague victims, smugglers, and now us. The energy is ancient. Can you feel it?","choices":[{"id":"c1a","text":"The history adds depth to every beat. I feel it.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"Dark spaces need dark sounds. I am ready.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Angus McBeat","text":"B2B in the main vault. Let us make the ghosts dance.","choices":[{"id":"c2","text":"Let us do it.","next_node_id":null}]}]', NULL, NULL),
('538f7841-a232-4c85-96ba-e03a52682a3f', 'hopeworks_promoter_lee', 'Steel City Sound', 'Lee runs the booking at Hope Works and wants fresh Sheffield talent.', 'one_time', 15, '{"cash": 280, "fame": 75, "xp": 28}', '[{"id":"d1","speaker":"Lee","text":"Sheffield invented electronic music with Warp Records and Cabaret Voltaire. Hope Works carries that torch. You got that industrial spirit?","choices":[{"id":"c1a","text":"Sheffield runs through my veins. Bleeps, bass, and grit.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I respect the legacy and I want to add to it.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Lee","text":"Warehouse floor, midnight slot. Make Sheffield proud.","choices":[{"id":"c2","text":"For the Steel City.","next_node_id":null}]}]', NULL, NULL),
('1fe91374-3036-4531-88fe-a8a642b5a763', 'digital_booker_sarah', 'Toon Takeover', 'Sarah books the main room at Digital and needs someone to headline a big night.', 'one_time', 20, '{"cash": 450, "fame": 110, "xp": 35}', '[{"id":"d1","speaker":"Sarah","text":"Digital is Newcastle beating heart. Geordies party harder than anyone in the UK. Can you match their energy?","choices":[{"id":"c1a","text":"I feed off crowd energy. The harder they go, the harder I go.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I will take them on a journey — peaks, valleys, and euphoria.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Sarah","text":"Saturday main room. 1am-3am. Bring everything you have got.","choices":[{"id":"c2","text":"Newcastle will not know what hit it.","next_node_id":null}]}]', NULL, NULL),
('6610817c-03c5-47d2-98f9-effb68fb939f', 'clwb_manager_rhys', 'Welsh Underground', 'Rhys manages Clwb Ifor Bach and champions Welsh electronic music.', 'one_time', 12, '{"cash": 200, "fame": 55, "xp": 22}', '[{"id":"d1","speaker":"Rhys","text":"Clwb Ifor Bach has three floors of pure Welsh passion. We celebrate local talent first. Where are you from?","choices":[{"id":"c1a","text":"I am here to learn from the Welsh scene and contribute.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"Music has no borders. Let me prove myself.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Rhys","text":"Top floor, Friday. Show us what you have got, friend.","choices":[{"id":"c2","text":"Diolch — thank you.","next_node_id":null}]}]', NULL, NULL),
('5f832a5f-db73-4443-b1d6-e927b7910460', 'patterns_curator_nina', 'Seaside Sessions', 'Nina curates the electronic nights beneath Brighton seafront arches.', 'one_time', 15, '{"cash": 300, "fame": 75, "xp": 28}', '[{"id":"d1","speaker":"Nina","text":"Brighton is the UK alternative capital. Patterns sits right on the beach — you can hear the waves between tracks. It is magic.","choices":[{"id":"c1a","text":"Music and nature intertwined. That is beautiful.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I will make a set that flows like the tide.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Nina","text":"Sunset session on the terrace. Then inside for the late show.","choices":[{"id":"c2","text":"Perfect progression.","next_node_id":null}]}]', NULL, NULL),
('eb3c6a22-5ee6-4d17-af61-e7e646247fa7', 'stealth_owner_kim', 'Bass Capital', 'Kim runs Stealth, Nottingham bass music headquarters.', 'one_time', 15, '{"cash": 280, "fame": 70, "xp": 28}', '[{"id":"d1","speaker":"Kim","text":"Stealth is bass music territory. DnB, dubstep, grime — if it does not rattle your chest, it does not belong here.","choices":[{"id":"c1a","text":"Bass is life. I will shake the foundations.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I bring bass music from a different angle. Let me surprise you.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Kim","text":"Friday, Room 2. Show Notts what you are made of.","choices":[{"id":"c2","text":"Bring the bass bins.","next_node_id":null}]}]', NULL, NULL),
('71df19be-b90c-4baa-9267-3d9bd6e9d0c6', 'limelight_vicar_pete', 'The Church Party', 'Pete manages Limelight, a converted Victorian church turned superclub.', 'one_time', 18, '{"cash": 400, "fame": 100, "xp": 32}', '[{"id":"d1","speaker":"Pete","text":"Limelight is literally a church. Stained glass windows, gothic arches, and 1500 people losing their minds. It is spiritual.","choices":[{"id":"c1a","text":"I will preach the gospel of house music.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"The acoustics must be incredible in here.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Pete","text":"Saturday main chapel. The congregation is waiting.","choices":[{"id":"c2","text":"Let us have church.","next_node_id":null}]}]', NULL, NULL),
('fde3def8-0438-4258-a210-2be5b746d0a3', 'colo_owner_marcus', 'Three Floor Challenge', 'Marcus Webb challenges you to play all three floors of The Colosseum in one night.', 'one_time', 25, '{"cash": 700, "fame": 180, "xp": 45}', '[{"id":"d1","speaker":"Marcus Webb","text":"The Colosseum has three floors, three vibes. Main room is big-room house, second is R and B, third is drum and bass. I need someone who can do all three.","choices":[{"id":"c1a","text":"Versatility is my superpower. I will crush all three.","next_node_id":"d2","effects":{"affinity":6}},{"id":"c1b","text":"That is a marathon. But I love a challenge.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Marcus Webb","text":"45 minutes per floor, no breaks. Start on the main floor. Go.","choices":[{"id":"c2","text":"Game on, Marcus.","next_node_id":null}]}]', NULL, NULL),
('09b3a66d-ebc8-41ce-8a56-bd0aeb2dc9e1', 'sound_curator_adam', 'LA Underground', 'Adam curates Sound underground program and wants fresh West Coast talent.', 'one_time', 18, '{"cash": 500, "fame": 130, "xp": 38}', '[{"id":"d1","speaker":"Adam","text":"Sound is where LA real underground lives. We do not do bottle service or VIP tables. Just pure sound, Funktion-One, and dancers who actually care about music.","choices":[{"id":"c1a","text":"That is exactly my vibe. Music first, always.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"LA needs more spaces like this. I want to be part of it.","next_node_id":"d2","effects":{"respect":5}}]},{"id":"d2","speaker":"Adam","text":"Opening set, Friday. Build the night right.","choices":[{"id":"c2","text":"From the ground up.","next_node_id":null}]}]', NULL, NULL);
